<span class="line"><span style="color:#CBA6F7;">        if</span><span style="color:#F38BA8;font-style:italic;"> self</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">should_condense</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">view</span><span style="color:#9399B2;">):</span></span>
